if (!defined('ABSPATH')) { exit; }
$css=<<<'CSS'
.zo-game-root--time-debt{max-width:860px;margin:0 auto;padding:18px;border-radius:24px;background:linear-gradient(180deg,#121827,#25324f);color:#eef4ff;font-family:"Trebuchet MS","Segoe UI",sans-serif}.zo-game-root--time-debt *{box-sizing:border-box}.td-top{display:grid;grid-template-columns:repeat(5,1fr);gap:10px;margin-bottom:14px}.td-stat,.td-panel{background:rgba(255,255,255,.08);border:1px solid rgba(255,255,255,.1);border-radius:16px;padding:12px}.td-stat strong{display:block;font-size:12px;text-transform:uppercase;color:#b8cbf2}.td-grid{display:grid;grid-template-columns:1.2fr .9fr;gap:14px}.td-board{display:grid;grid-template-columns:repeat(4,1fr);gap:10px}.td-tile{aspect-ratio:1;border:0;border-radius:16px;background:#3d5c99;color:#fff;font-size:28px;font-weight:700;cursor:pointer}.td-decoy{background:#6e4457}.td-btns{display:flex;flex-wrap:wrap;gap:8px;margin-top:10px}.td-btn{border:0;border-radius:12px;padding:10px 14px;background:#ff9b54;color:#1b2130;font-weight:700;cursor:pointer}@media (max-width:760px){.td-grid{grid-template-columns:1fr}.td-top{grid-template-columns:repeat(2,1fr)}}
CSS;
$js=<<<'JS'
document.addEventListener('DOMContentLoaded',function(){document.querySelectorAll('.zo-game-root--time-debt').forEach(function(root){const stageEl=root.querySelector('[data-stage]'),timeEl=root.querySelector('[data-time]'),debtEl=root.querySelector('[data-debt]'),hardEl=root.querySelector('[data-hard]'),goalEl=root.querySelector('[data-goal]'),boardEl=root.querySelector('[data-board]'),logEl=root.querySelector('[data-log]');let timer=0,interval=0,state;function reset(){state={stage:1,debt:0,hardness:0,targetsLeft:0,playing:false};clearInterval(interval);renderBoard([]);logEl.textContent='Clear 3 sections. Borrowing 5 seconds now adds more targets and decoys later.';update()}function stageConfig(){const base=[4,5,6][state.stage-1]||6;return{targets:base+Math.floor(state.debt/5)+state.hardness,decoys:(state.stage>1?1:0)+Math.floor(state.debt/10),time:10-state.hardness+Math.min(4,Math.floor(state.debt/8))}}function startStage(){const cfg=stageConfig();state.playing=true;state.targetsLeft=cfg.targets;timer=cfg.time;const tiles=[];for(let i=0;i<cfg.targets;i++)tiles.push({type:'target',label:String(i+1)});for(let i=0;i<cfg.decoys;i++)tiles.push({type:'decoy',label:'X'});while(tiles.length<12)tiles.push({type:'blank',label:''});tiles.sort(()=>Math.random()-.5);renderBoard(tiles);clearInterval(interval);interval=setInterval(function(){timer=Math.max(0,timer-1);update();if(timer===0){clearInterval(interval);state.playing=false;logEl.textContent='Time collectors caught up to you. Restart and borrow less.'}},1000);logEl.textContent='Stage '+state.stage+' started. Clear all blue tiles before time runs out.';update()}function borrow(){if(!state.playing)return;timer+=5;state.debt+=5;state.hardness+=1;logEl.textContent='You borrowed 5 seconds. Future sections just got meaner.';update()}function clickTile(btn){if(!state.playing)return;if(btn.dataset.type==='target'){btn.disabled=true;btn.style.visibility='hidden';state.targetsLeft--;if(state.targetsLeft===0){clearInterval(interval);state.playing=false;if(state.stage===3){logEl.textContent='You escaped the timeline with debt of '+state.debt+' seconds.'}else{state.stage++;state.hardness+=Math.floor(state.debt/10);logEl.textContent='Section cleared. Your debt follows you into the next room.'}update()}}else if(btn.dataset.type==='decoy'){timer=Math.max(0,timer-2);logEl.textContent='Decoy pressed. The future takes 2 seconds back.';update()}}function renderBoard(tiles){boardEl.innerHTML='';tiles.forEach(function(t){const b=document.createElement('button');b.className='td-tile'+(t.type==='decoy'?' td-decoy':'');b.textContent=t.label;b.dataset.type=t.type;b.disabled=t.type==='blank';b.addEventListener('click',function(){clickTile(b)});boardEl.appendChild(b)})}function update(){const cfg=stageConfig();stageEl.textContent=String(state.stage);timeEl.textContent=String(timer);debtEl.textContent=state.debt+'s';hardEl.textContent='+'+state.hardness;goalEl.textContent=state.playing?state.targetsLeft+' left':(state.stage>3?'done':'ready')}}root.querySelector('[data-start]').addEventListener('click',function(){if(state.stage<=3)startStage()});root.querySelector('[data-borrow]').addEventListener('click',borrow);root.querySelector('[data-next]').addEventListener('click',function(){if(!state.playing&&state.stage<=3)startStage()});root.querySelector('[data-restart]').addEventListener('click',reset);reset()})});
JS;
if(!function_exists('zo_game_time_debt_render')){function zo_game_time_debt_render($post_id=0,$module=array()){ob_start();?>
<div class="zo-game-root zo-game-root--time-debt">
<h2>Time Debt</h2><p>Borrow seconds from your future. Every loan makes the next section harder.</p>
<div class="td-top"><div class="td-stat"><strong>Stage</strong><span data-stage>1</span></div><div class="td-stat"><strong>Time</strong><span data-time>0</span></div><div class="td-stat"><strong>Debt</strong><span data-debt>0s</span></div><div class="td-stat"><strong>Hardness</strong><span data-hard>+0</span></div><div class="td-stat"><strong>Goal</strong><span data-goal>ready</span></div></div>
<div class="td-grid"><div class="td-board" data-board></div><div class="td-panel"><strong>Rules</strong><p>Blue tiles are real. Red tiles are decoys. Borrowing gives 5 seconds immediately, but adds pain to later rooms.</p><div class="td-btns"><button class="td-btn" data-start>Start Stage</button><button class="td-btn" data-borrow>Borrow 5s</button><button class="td-btn" data-next>Next Stage</button><button class="td-btn" data-restart>Restart</button></div><p data-log></p></div></div>
</div>
<?php return ob_get_clean();}}
return array('slug'=>'time-debt','name'=>'Time Debt','author'=>'Arslan','description'=>'Borrow seconds from your future and survive the harder sections your debt creates.','render_callback'=>'zo_game_time_debt_render','inline_style'=>$css,'inline_script'=>$js);
